mapper.update:
BEGIN
    EXECUTE IMMEDIATE '
        CREATE TABLE TEST_FLOW_TASKLET_HISTORY (
            ID NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
            JOB_EXECUTION_ID NUMBER(19,0),
            STEP_NAME VARCHAR2(100),
            BRANCH_CODE VARCHAR2(30),
            DETAIL_MESSAGE VARCHAR2(500),
            CREATED_AT TIMESTAMP DEFAULT SYSTIMESTAMP
        )';
EXCEPTION
    WHEN OTHERS THEN
        IF SQLCODE != -955 THEN
            RAISE;
        END IF;
END;
